code.C:
#include <stdio.h>
int main() {
    int num = 1;
    while (num <= 5) {
        printf("%d", num * num);
        if (num < 5) printf(" ");
        num++;
    }
    printf("\n");
    return 0;
}

code.C++:
#include <iostream>
using namespace std;
int main() {
    int num = 1;
    while (num <= 5) {
        cout << num * num;
        if (num < 5) cout << " ";
        ++num;
    }
    cout << endl;
    return 0;
}

